  ('citrus-vinegar-cleaner', 'Citrus Vinegar All-Purpose Cleaner', 'Cleaning', 'cleaning', 'Easy', '10 min', '["Orange or lemon peels (enough to fill a jar)", "White vinegar (to cover)"]'::jsonb, '["Fill a jar with citrus peels.", "Cover completely with white vinegar.", "Seal and let sit 10–14 days in a cool, dark place.", "Strain out the peels.", "Dilute 1:1 with water in a spray bottle."]'::jsonb, true, '$5–$10 saved', '["kitchen", "all-purpose", "natural", "pantry-magic"]'::jsonb, 'catalog', true, true),
  ('hydrogen-peroxide-mold-spray', 'Hydrogen Peroxide Mold Spray', 'Cleaning', 'cleaning', 'Easy', '15 min', '["3% hydrogen peroxide (about 1 cup)"]'::jsonb, '["Pour 3% hydrogen peroxide into a spray bottle.", "Spray directly onto mold spots until saturated.", "Let sit for 10 minutes.", "Scrub gently with a brush, then rinse with clean water."]'::jsonb, false, '$4–$7 saved', '["bathroom", "mold", "antibacterial", "pantry-magic"]'::jsonb, 'catalog', true, true),
  ('diy-toilet-bombs', 'DIY Toilet Bombs', 'Cleaning', 'cleaning', 'Easy', '20 min', '["1 cup baking soda", "1/4 cup citric acid", "Water (in a spray bottle, for misting)"]'::jsonb, '["Mix baking soda and citric acid in a bowl.", "Lightly mist with water until the mixture is just moldable (don''t overdo it or it''ll fizz).", "Press firmly into silicone molds.", "Let dry overnight, then pop out and store in a sealed jar."]'::jsonb, true, '$6–$12 saved', '["bathroom", "toilet", "odor"]'::jsonb, 'catalog', true, false),
  ('castile-soap-floor-cleaner', 'Castile Soap Floor Cleaner', 'Cleaning', 'cleaning', 'Easy', '10 min', '["1 gallon warm water", "1 tbsp castile soap"]'::jsonb, '["Fill a bucket with warm water.", "Add the castile soap and stir gently to combine.", "Mop floors as usual — no rinse needed."]'::jsonb, true, '$5–$9 saved', '["floors", "wood", "tile", "pantry-magic"]'::jsonb, 'catalog', true, true),
  ('stainless-steel-polish', 'Stainless Steel Polish', 'Cleaning', 'cleaning', 'Easy', '5 min', '["White vinegar", "Olive oil"]'::jsonb, '["Wipe stainless surface with vinegar on a soft cloth.", "Buff with a small amount of olive oil along the grain.", "Wipe off any excess for a streak-free shine."]'::jsonb, true, '$3–$6 saved', '["kitchen", "appliances", "pantry-magic"]'::jsonb, 'catalog', true, true),
